researcher_llm = ChatAnthropic(model="claude-haiku-4-5-20251001")
writer_llm     = ChatAnthropic(model="claude-sonnet-5")

def researcher_node(state: PipelineState) -> dict:
    """Searches and retrieves relevant information for the task."""
    try:
        resp = researcher_llm.invoke([
            {"role": "system", "content": "Retrieve key facts and sources for the given task."},
            {"role": "user", "content": state["task"]},
        ])
        return {"research": resp.content}
    except Exception as exc:
        return {"research": "", "errors": [f"researcher:{exc}"]}

def analyst_node(state: PipelineState) -> dict:
    """Classifies and structures the research output."""
    if not state["research"]:
        return {"analysis": "", "errors": ["analyst:no research available"]}
    resp = researcher_llm.invoke([
        {"role": "system", "content": "Classify and structure the following research into key themes."},
        {"role": "user", "content": state["research"]},
    ])
    return {"analysis": resp.content}

def writer_node(state: PipelineState) -> dict:
    """Drafts a response using research and analysis."""
    context = f"""Task: {state['task']}
Research: {state['research']}
Analysis: {state['analysis']}"""
    resp = writer_llm.invoke([
        {"role": "system", "content": "Write a clear, accurate response to the task using the provided context."},
        {"role": "user", "content": context},
    ])
    return {"draft": resp.content}

def reviewer_node(state: PipelineState) -> dict:
    """Reviews the draft for accuracy and completeness."""
    resp = researcher_llm.invoke([
        {"role": "system", "content": "Review this draft and provide a brief quality assessment."},
        {"role": "user", "content": state["draft"]},
    ])
    # Treat reviewer feedback as the final output
    return {"review": resp.content, "final": state["draft"]}

class PipelineStateWithGuard(PipelineState):
    steps: int              # incremented by supervisor every turn

MAX_STEPS = 12

def supervisor_node_guarded(state: PipelineStateWithGuard) -> dict:
    if state["steps"] >= MAX_STEPS:
        return {"next": "FINISH", "errors": ["supervisor:step_limit_exceeded"]}
    # ... same routing logic as before ...
    choice = _pick_worker(state)
    return {"next": choice, "steps": state["steps"] + 1}

def route_guarded(state: PipelineStateWithGuard):
    if state["next"] == "FINISH" or state["steps"] >= MAX_STEPS:
        return END
    return state["next"]
